const OPENAI = 'TU_OPENAI_API_KEY';

const TOMORROW = new Date(Date.now() + 864e5).toISOString().split('T')[0];
const url = `${BASE}/rest/v1/appointments?barbershop_id=eq.${BARBERSHOP_ID}&appointment_date=eq.${TOMORROW}&status=in.(scheduled,confirmed,pending)&select=id,start_time,end_time,clients(name,phone),services(name,duration_minutes,price),barbers(name)&order=start_time.asc`;

return [{ json: { barbershop_id: BARBERSHOP_ID, tomorrow: TOMORROW, base: BASE, key: KEY, openai: OPENAI, url } }];

const appts = $input.first().json;
const list = Array.isArray(appts) ? appts : [appts];
const a = list[0];
if (!a || !a.clients) return [];

const hora = a.start_time?.slice(0,5) || 'tu hora';
const cliente = a.clients?.name || 'Cliente';
const servicio = a.services?.name || 'el servicio';
const barbero = a.barbers?.name || 'tu barbero';
const precio = a.services?.price ? ` (${a.services.price}€)` : '';
const phone = a.clients?.phone || '';

const cfg = $('📅 Configurar fechas').item.json;

return [{ json: {
  phone,
  cliente,
  hora,
  appointment_id: a.id,
  openai_key: cfg.openai,
  barbershop_id: cfg.barbershop_id,
  prompt_user: `Genera un recordatorio de WhatsApp para ${cliente} que tiene cita mañana a las ${hora} para ${servicio}${precio} con ${barbero}. Máximo 2 líneas, amable y profesional, en español.`
}}];

const phone = $('🧠 Construir mensaje recordatorio').item.json.phone;
const cliente = $('🧠 Construir mensaje recordatorio').item.json.cliente;
const hora = $('🧠 Construir mensaje recordatorio').item.json.hora;
const raw = $input.first().json;
const aiMsg = raw.choices?.[0]?.message?.content || `Hola ${cliente}, te recordamos tu cita mañana a las ${hora}. ¡Te esperamos!`;
return [{ json: { phone, cliente, hora, message: aiMsg } }];
